blocks.en:
flowchart TD
  A[Mesh frame received] --> B{From peer mesh STA?}
  B -- No --> X[Discard silently]
  B -- Yes --> C{Duplicate? check Mesh SA + Seq}
  C -- Yes --> X
  C -- No --> D{Addr3 = my address?}
  D -- Yes --> E[Deliver up to LLC]
  D -- No --> F[Decrement Mesh TTL]
  F --> G{TTL = 0 or no forwarding?}
  G -- Yes --> X
  G -- No --> H[Forward to next hop]

blocks.zh:
flowchart TD
  A[收到 mesh 帧] --> B{来自对等 mesh STA?}
  B -- 否 --> X[静默丢弃]
  B -- 是 --> C{重复帧? 查 Mesh SA + 序列号}
  C -- 是 --> X
  C -- 否 --> D{地址3 = 本机地址?}
  D -- 是 --> E[上交 LLC]
  D -- 否 --> F[Mesh TTL 减 1]
  F --> G{TTL = 0 或不转发?}
  G -- 是 --> X
  G -- 否 --> H[转发到下一跳]
